/**
 * Email notification adapter — delivers notifications via email.
 *
 * Implements NotificationAdapter interface per the event-driven notification
 * architecture. Registered with NotificationService at startup.
 *
 * Features:
 * - Template rendering: maps NotificationType to HTML/text email templates
 * - Recipient resolution: validates and normalizes email addresses
 * - Configurable transport: supports pluggable send functions for testing/production
 * - Error handling: never throws, returns failed NotificationResult on errors
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult, NotificationType } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Represents a fully rendered email ready for sending.
 */
export interface EmailMessage {
  to: string;
  subject: string;
  htmlBody: string;
  textBody: string;
  sentAt: Date;
}

/**
 * Email template with HTML and plain-text variants.
 */
export interface EmailTemplate {
  subject: (vars: TemplateVariables) => string;
  html: (vars: TemplateVariables) => string;
  text: (vars: TemplateVariables) => string;
}

/**
 * Variables available to email templates.
 */
export interface TemplateVariables {
  recipient: string;
  subject: string;
  body: string;
  type: NotificationType;
  notificationId: string;
  metadata?: Record<string, unknown>;
}

/**
 * Configuration for the EmailAdapter.
 */
export interface EmailAdapterConfig {
  /** Sender address for outgoing emails */
  fromAddress: string;
  /** Application name used in templates */
  appName: string;
  /** Custom send function — defaults to in-memory logging */
  sendFn?: (message: EmailMessage) => Promise<void>;
}

const DEFAULT_CONFIG: EmailAdapterConfig = {
  fromAddress: 'noreply@taskflowpro.com',
  appName: 'TaskFlow Pro',
};

/**
 * Built-in email templates keyed by notification type.
 */
const templates: Record<NotificationType, EmailTemplate> = {
  'order-confirmation': {
    subject: (vars) => vars.subject,
    html: (vars) =>
      `<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">` +
      `<h2>Order Confirmation</h2>` +
      `<p>${escapeHtml(vars.body)}</p>` +
      `<p style="color: #666; font-size: 12px;">Notification ID: ${vars.notificationId}</p>` +
      `</div>`,
    text: (vars) => `Order Confirmation\n\n${vars.body}\n\nNotification ID: ${vars.notificationId}`,
  },
  'order-status-update': {
    subject: (vars) => vars.subject,
    html: (vars) =>
      `<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">` +
      `<h2>Order Status Update</h2>` +
      `<p>${escapeHtml(vars.body)}</p>` +
      `<p style="color: #666; font-size: 12px;">Notification ID: ${vars.notificationId}</p>` +
      `</div>`,
    text: (vars) => `Order Status Update\n\n${vars.body}\n\nNotification ID: ${vars.notificationId}`,
  },
  'user-welcome': {
    subject: (vars) => vars.subject,
    html: (vars) =>
      `<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">` +
      `<h2>Welcome!</h2>` +
      `<p>${escapeHtml(vars.body)}</p>` +
      `<p style="color: #666; font-size: 12px;">Notification ID: ${vars.notificationId}</p>` +
      `</div>`,
    text: (vars) => `Welcome!\n\n${vars.body}\n\nNotification ID: ${vars.notificationId}`,
  },
  'user-profile-update': {
    subject: (vars) => vars.subject,
    html: (vars) =>
      `<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">` +
      `<h2>Profile Updated</h2>` +
      `<p>${escapeHtml(vars.body)}</p>` +
      `<p style="color: #666; font-size: 12px;">Notification ID: ${vars.notificationId}</p>` +
      `</div>`,
    text: (vars) => `Profile Updated\n\n${vars.body}\n\nNotification ID: ${vars.notificationId}`,
  },
};

/**
 * Simple HTML escaping to prevent XSS in email templates.
 */
function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

/**
 * Validate that a string looks like a valid email address.
 */
function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

/**
 * Normalize an email address: trim whitespace and lowercase.
 */
function normalizeEmail(email: string): string {
  return email.trim().toLowerCase();
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: EmailMessage[] = [];
  private config: EmailAdapterConfig;

  constructor(config?: Partial<EmailAdapterConfig>) {
    this.config = { ...DEFAULT_CONFIG, ...config };
  }

  /**
   * Resolve and validate the recipient email address.
   * Returns the normalized email or null if invalid.
   */
  resolveRecipient(recipient: string): string | null {
    const normalized = normalizeEmail(recipient);
    if (!isValidEmail(normalized)) {
      this.logger.warn(`Invalid email address: ${recipient}`);
      return null;
    }
    return normalized;
  }

  /**
   * Render a notification payload into an EmailMessage using the appropriate template.
   */
  renderTemplate(payload: NotificationPayload): { htmlBody: string; textBody: string; subject: string } {
    const template = templates[payload.type];
    const vars: TemplateVariables = {
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      type: payload.type,
      notificationId: payload.id,
      metadata: payload.metadata,
    };

    return {
      subject: template.subject(vars),
      htmlBody: template.html(vars),
      textBody: template.text(vars),
    };
  }

  /**
   * Send a notification through the email channel.
   * Never throws — returns a failed NotificationResult on error.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // Resolve recipient
      const resolvedRecipient = this.resolveRecipient(payload.recipient);
      if (!resolvedRecipient) {
        return {
          success: false,
          notificationId: payload.id,
          channel: 'email',
          error: `Invalid email address: ${payload.recipient}`,
          deliveredAt: new Date(),
        };
      }

      // Render template
      const rendered = this.renderTemplate(payload);

      // Build email message
      const email: EmailMessage = {
        to: resolvedRecipient,
        subject: rendered.subject,
        htmlBody: rendered.htmlBody,
        textBody: rendered.textBody,
        sentAt: new Date(),
      };

      // Send via transport
      if (this.config.sendFn) {
        await this.config.sendFn(email);
      }

      this.sentEmails.push(email);
      this.logger.info(`Email sent to ${resolvedRecipient}: ${email.subject}`);

      return {
        success: true,
        notificationId: payload.id,
        channel: 'email',
        deliveredAt: email.sentAt,
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : String(err);
      this.logger.error(`Failed to send email to ${payload.recipient}: ${errorMessage}`);
      return {
        success: false,
        notificationId: payload.id,
        channel: 'email',
        error: errorMessage,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    priority: 'normal',
    createdAt: new Date(),
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;

  beforeEach(() => {
    adapter = new EmailAdapter();
  });

  describe('send', () => {
    it('should send an email successfully', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('email');
      expect(result.deliveredAt).toBeInstanceOf(Date);
    });

    it('should store sent emails for inspection', async () => {
      await adapter.send(makePayload());

      const emails = adapter.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.subject).toBe('Order Confirmation: order-1');
    });

    it('should accumulate multiple sent emails', async () => {
      await adapter.send(makePayload({ id: 'notif-0001' }));
      await adapter.send(makePayload({ id: 'notif-0002', recipient: 'bob@example.com' }));

      expect(adapter.getSentEmails()).toHaveLength(2);
    });

    it('should clear sent emails', async () => {
      await adapter.send(makePayload());
      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });

  describe('recipient resolution', () => {
    it('should normalize email to lowercase', async () => {
      await adapter.send(makePayload({ recipient: 'Alice@Example.COM' }));

      const emails = adapter.getSentEmails();
      expect(emails[0]?.to).toBe('alice@example.com');
    });

    it('should trim whitespace from email', async () => {
      await adapter.send(makePayload({ recipient: '  alice@example.com  ' }));

      const emails = adapter.getSentEmails();
      expect(emails[0]?.to).toBe('alice@example.com');
    });

    it('should reject invalid email addresses', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-an-email' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email address');
      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should reject empty email addresses', async () => {
      const result = await adapter.send(makePayload({ recipient: '' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email address');
    });

    it('should resolve valid recipient via resolveRecipient', () => {
      expect(adapter.resolveRecipient('Alice@Example.COM')).toBe('alice@example.com');
    });

    it('should return null for invalid recipient via resolveRecipient', () => {
      expect(adapter.resolveRecipient('invalid')).toBeNull();
    });
  });

  describe('template rendering', () => {
    it('should render order-confirmation template with HTML', async () => {
      await adapter.send(makePayload({ type: 'order-confirmation' }));

      const emails = adapter.getSentEmails();
      expect(emails[0]?.htmlBody).toContain('Order Confirmation');
      expect(emails[0]?.htmlBody).toContain('notif-0001');
    });

    it('should render order-status-update template', async () => {
      await adapter.send(makePayload({
        type: 'order-status-update',
        subject: 'Order Update: order-1',
        body: 'Your order status has changed from pending to confirmed.',
      }));

      const emails = adapter.getSentEmails();
      expect(emails[0]?.htmlBody).toContain('Order Status Update');
      expect(emails[0]?.textBody).toContain('pending to confirmed');
    });

    it('should render user-welcome template', async () => {
      await adapter.send(makePayload({
        type: 'user-welcome',
        subject: 'Welcome to TaskFlow Pro!',
        body: 'Hi Alice, welcome to TaskFlow Pro.',
      }));

      const emails = adapter.getSentEmails();
      expect(emails[0]?.htmlBody).toContain('Welcome!');
      expect(emails[0]?.textBody).toContain('Hi Alice');
    });

    it('should render user-profile-update template', async () => {
      await adapter.send(makePayload({
        type: 'user-profile-update',
        subject: 'Profile Updated',
        body: 'Your profile has been updated.',
      }));

      const emails = adapter.getSentEmails();
      expect(emails[0]?.htmlBody).toContain('Profile Updated');
    });

    it('should include both HTML and plain-text bodies', async () => {
      await adapter.send(makePayload());

      const emails = adapter.getSentEmails();
      expect(emails[0]?.htmlBody).toContain('<');
      expect(emails[0]?.textBody).not.toContain('<div');
    });

    it('should escape HTML in body content', () => {
      const payload = makePayload({ body: '<script>alert("xss")</script>' });
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.htmlBody).not.toContain('<script>');
      expect(rendered.htmlBody).toContain('&lt;script&gt;');
    });

    it('should include notification ID in rendered output', () => {
      const rendered = adapter.renderTemplate(makePayload());

      expect(rendered.htmlBody).toContain('notif-0001');
      expect(rendered.textBody).toContain('notif-0001');
    });
  });

  describe('custom transport', () => {
    it('should call custom sendFn when provided', async () => {
      const sent: Array<{ to: string }> = [];
      const customAdapter = new EmailAdapter({
        sendFn: async (msg) => { sent.push({ to: msg.to }); },
      });

      await customAdapter.send(makePayload());

      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('alice@example.com');
    });

    it('should return failure when sendFn throws', async () => {
      const customAdapter = new EmailAdapter({
        sendFn: async () => { throw new Error('SMTP connection failed'); },
      });

      const result = await customAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMTP connection failed');
      expect(customAdapter.getSentEmails()).toHaveLength(0);
    });

    it('should still store email when using default transport', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentEmails()).toHaveLength(1);
    });
  });

  describe('channel property', () => {
    it('should report email as its channel', () => {
      expect(adapter.channel).toBe('email');
    });
  });
});

